INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-f29af906-moex-00118', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，土地總登記於審查後直轄市或縣（市）地政機關應即公告，有關公告之敘述下列何者錯誤？', '["接受聲請或囑託登記之件，經審查證明無誤，應即公告之，其期間不得少於15日", "逾登記期限無人聲請登記之土地或經聲請而逾限未補繳證明文件者，其土地視為無主土地，公告期滿， 無人提出異議，即為國有土地之登記，其期間不得少於30日", "土地權利關係人，在公告期間內，如有異議，得向該管直轄市或縣（市）地政機關以書面提出，並應附 具證明文件", "因異議而生土地權利爭執時，應由該管直轄市或縣（市）地政機關予以調處，不服調處者，應於接到調 處通知後30日內，向司法機關訴請處理，逾期不起訴者，依原調處結果辦理之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00119', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，有關土地登記損害賠償之規定，下列敘述何者錯誤？', '["因登記錯誤遺漏或虛偽致受損害者，由該地政機關負損害賠償責任。但該地政機關證明其原因應歸責於 受害人時，不在此限", "損害賠償除可請求實際損失外，尚得請求精神賠償及其他損失利益", "損害賠償之請求，如經該地政機關拒絕，受損害人得向司法機關起訴", "地政機關所負之損害賠償，如因登記人員之重大過失所致者，由該人員償還，撥歸登記儲金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00120', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，政府機關得囑託登記機關登記之情形，下列何者非屬之？', '["因土地徵收或撥用之登記", "依第144條規定之塗銷登記", "照價收買土地之登記", "因土地重測或重劃確定之登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00121', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，登記可由權利人或登記名義人單獨申請，下列何者非屬之？', '["土地權利信託登記", "預告登記或塗銷登記", "建物所有權第一次登記", "更名或住址變更登記"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00122', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '有關私有土地最小面積限制之規定，下列敘述何者錯誤？', '["直轄市或縣（市）地政機關於其管轄區內之土地，得斟酌地方經濟情形，依其性質及使用之種類，為最 小面積單位之規定，並禁止其再分割", "每宗耕地分割後每人所有面積未達0.5公頃者，不得分割", "耕地三七五租約，租佃雙方協議以分割方式終止租約者，得分割為租佃雙方單獨所有", "每宗耕地部分依法變更為非耕地使用者，其依法變更部分及共有分管之未變更部分，得為分割"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00123', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，下列何者非屬公有土地？', '["國有土地", "原住民保留地", "直轄市有土地", "鄉（鎮、市）有土地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00124', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法第34條之1第4項所規定之優先購買權效力，下列敘述何者錯誤？', '["具有物權之法律效力", "共有人間應有部分土地互為買賣，他共有人無優先購買權", "共有人違反法律規定未先徵求他共有人放棄優先購買權，而將應有部分賣與他人，並已依法移轉所有權 登記時，他共有人不得主張該買賣契約為無效而塗銷其依法所為之登記", "若與土地法第104條規定之基地或房屋出賣時的優先購買權競合時，應優先適用土地法第104條"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00125', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '大陸地區人民、法人、團體或其他機構，或陸資公司申請在臺灣地區取得、設定或移轉不動產物權，依據 大陸地區人民在臺灣地區取得設定或移轉不動產物權許可辦法之規定，有不予許可之情形，下列何者不屬之？', '["影響國家重大建設", "涉及土地壟斷投機或炒作", "大陸地區在臺金融機構辦理授信業務", "影響國土整體發展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00126', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '有關私有土地所有權取得之限制，依土地法規定禁止私有之土地，下列何者不屬之？', '["礦泉地", "瀑布地", "公共需用之水源地", "森林地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00127', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '有關土地法對外國人取得我國土地權利之規定，下列敘述何者錯誤？', '["林地、漁地、狩獵地、鹽地、礦地、水源地、要塞軍備區域及領域邊境之土地，不得移轉、設定負擔或 租賃於外國人", "外國人依規定取得土地，應檢附相關文件，申請該管直轄市或縣（市）政府核准；土地有變更用途或為 繼承以外之移轉時，亦同", "外國人依規定取得土地，應依核定期限及用途使用，因故未能依核定期限使用者，應敘明原因向中央目 的事業主管機關申請展期；其未依核定期限及用途使用者，由直轄市或縣（市）政府通知土地所有權人 於通知送達後3年內出售", "外國人租賃或購買土地，其面積及所在地點應受中央地政主管機關依法所定之限制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
